mapper.select:
SELECT *
FROM biz_risk_event
WHERE source_type = #{sourceType}
  AND source_id = #{sourceId}
LIMIT 1

SELECT e.*,
       reporter.username AS reporter_name,
       resolver.username AS resolver_name,
       r.reason_detail AS report_reason_detail
FROM biz_risk_event e
         LEFT JOIN biz_report r ON e.report_id = r.id
         LEFT JOIN sys_user reporter ON r.reporter_id = reporter.user_id
         LEFT JOIN sys_user resolver ON e.resolved_by = resolver.user_id


        AND e.target_type = #{targetType}


        AND e.target_id = #{targetId}


        AND e.event_status = #{eventStatus}


        AND e.action_type = #{actionType}


        AND e.create_time >= #{startTime}


        AND e.create_time <= #{endTime}


ORDER BY e.create_time DESC
